/**
 * Google Dorks Documentation - Comprehensive Reference
 * 200+ examples for OSINT operators and techniques
 */

export interface DorkOperator {
    name: string;
    syntax: string;
    description: string;
    examples: string[];
    tips?: string;
    engines: ('google' | 'bing' | 'duckduckgo')[];
}

export interface DorkExample {
    name: string;
    query: string;
    description: string;
    category: string;
}

